import 'package:equatable/equatable.dart'; import '../../../../core/utils/date_parser.dart'; import '../../../../core/utils/map_utils.dart';
enum ReviewRating{one(1),two(2),three(3),four(4),five(5); final int value; const ReviewRating(this.value);}
class Review extends Equatable{final String id,reviewerId,sellerId,productId,comment; final String? chatRoomId; final ReviewRating rating; final bool isEdited,isHidden; final DateTime createdAt,updatedAt; const Review({required this.id,required this.reviewerId,required this.sellerId,required this.productId,this.chatRoomId,required this.rating,required this.comment,this.isEdited=false,this.isHidden=false,required this.createdAt,required this.updatedAt}); bool get isPositive=>rating.value>=4; bool get isNegative=>rating.value<=2; factory Review.fromMap(String id,Map<String,dynamic> map){final rv=MapUtils.intValue(map,'rating',fallback:5); return Review(id:id,reviewerId:MapUtils.stringValue(map,'reviewerId'),sellerId:MapUtils.stringValue(map,'sellerId'),productId:MapUtils.stringValue(map,'productId'),chatRoomId:map['chatRoomId'] as String?,rating:ReviewRating.values.firstWhere((e)=>e.value==rv,orElse:()=>ReviewRating.five),comment:MapUtils.stringValue(map,'comment'),isEdited:MapUtils.boolValue(map,'isEdited'),isHidden:MapUtils.boolValue(map,'isHidden'),createdAt:DateParser.fromValue(map['createdAt'])??DateTime.now(),updatedAt:DateParser.fromValue(map['updatedAt'])??DateTime.now());} Map<String,dynamic> toMap()=>{'reviewerId':reviewerId,'sellerId':sellerId,'productId':productId,'chatRoomId':chatRoomId,'rating':rating.value,'comment':comment,'isEdited':isEdited,'isHidden':isHidden,'createdAt':createdAt.toIso8601String(),'updatedAt':updatedAt.toIso8601String()}; @override List<Object?> get props=>[id,reviewerId,sellerId,productId,chatRoomId,rating,comment,isEdited,isHidden,createdAt,updatedAt];}
